const sb = {
  from: (table) => ({
    select: (cols = "*") => fetch(`${SUPABASE_URL}/rest/v1/${table}?select=${cols}`, {
      headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json" }
    }).then(r => r.json()),
    insert: (data) => fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
      method: "POST",
      headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json", Prefer: "return=representation" },
      body: JSON.stringify(data)
    }).then(r => r.json()),
    update: (data) => ({
      eq: (col, val) => fetch(`${SUPABASE_URL}/rest/v1/${table}?${col}=eq.${val}`, {
        method: "PATCH",
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json", Prefer: "return=representation" },
        body: JSON.stringify(data)
      }).then(r => r.json())
    }),
    delete: () => ({
      eq: (col, val) => fetch(`${SUPABASE_URL}/rest/v1/${table}?${col}=eq.${val}`, {
        method: "DELETE",
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` }
      })
    }),
    eq: (col, val) => ({
      select: (cols = "*") => fetch(`${SUPABASE_URL}/rest/v1/${table}?${col}=eq.${val}&select=${cols}`, {
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` }
      }).then(r => r.json()),
      single: () => fetch(`${SUPABASE_URL}/rest/v1/${table}?${col}=eq.${val}&select=*`, {
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` }
      }).then(r => r.json()).then(d => Array.isArray(d) ? d[0] : d)
    }),
  }),
  rpc: (fn, params) => fetch(`${SUPABASE_URL}/rest/v1/rpc/${fn}`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json" },
    body: JSON.stringify(params)
  }).then(r => r.json()),
};

// Setup tables via SQL through the REST API (run once)
async function setupTables() {
  const queries = [
    `CREATE TABLE IF NOT EXISTS users (
      id BIGSERIAL PRIMARY KEY,
      name TEXT NOT NULL,
      email TEXT UNIQUE,
      password TEXT NOT NULL,
      role TEXT NOT NULL DEFAULT 'student',
      phone TEXT,
      plan TEXT DEFAULT 'Mensual',
      plan_expiry DATE,
      classes_total INT DEFAULT 12,
      classes_done INT DEFAULT 0,
      notes TEXT DEFAULT '',
      created_at TIMESTAMPTZ DEFAULT NOW()
    )`,
    `CREATE TABLE IF NOT EXISTS payments (
      id BIGSERIAL PRIMARY KEY,
      user_id BIGINT REFERENCES users(id) ON DELETE CASCADE,
      date DATE NOT NULL,
      amount NUMERIC NOT NULL,
      concept TEXT NOT NULL,
      status TEXT DEFAULT 'Pagado',
      created_at TIMESTAMPTZ DEFAULT NOW()
    )`,
    `INSERT INTO users (name, email, password, role) VALUES
      ('Admin', 'admin@elitepadel.com', 'admin123', 'admin'),
      ('Carlos Gavio', 'carlos@elitepadel.com', 'coach123', 'coach'),
      ('Lic. Nahuel Reyes', 'nahuel@elitepadel.com', 'nahuel123', 'coach')
    ON CONFLICT (email) DO NOTHING`,
  ];
  for (const sql of queries) {
    await fetch(`${SUPABASE_URL}/rest/v1/rpc/exec_sql`, {
      method: "POST",
      headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json" },
      body: JSON.stringify({ sql })
    });
  }
}

