// ─── HELPERS ─────────────────────────────────────────────────────────────────
function daysUntil(dateStr) {
  if (!dateStr) return 999;
  const diff = new Date(dateStr) - new Date();
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
}
function StatusBadge({ days }) {
  if (days < 0) return <span style={badge("red")}>Vencido</span>;
  if (days <= 7) return <span style={badge("orange")}>Vence en {days}d</span>;
  return <span style={badge("green")}>Activo ({days}d)</span>;
}
function badge(color) {
  const colors = { green:{bg:"#dcfce7",text:"#166534"}, orange:{bg:"#fff7ed",text:"#9a3412"}, red:{bg:"#fee2e2",text:"#991b1b"} };
  return { padding:"2px 10px", borderRadius:20, fontSize:12, fontWeight:700, background:colors[color].bg, color:colors[color].text };
}
function LogoMark({ size = 40 }) {
  return <img src={LOGO_B64} width={size} height={size} style={{objectFit:"contain", background:"white", borderRadius:6, padding:2}} alt="Élite Pádel Academy" />;
}
